import type {IKitsPhoneInput} from "@lmb-it/kitsconcerto-types";
import {KitsContainer, KitsInputText, Image, Icon} from "../../../_compat";
import {useImperativeHandle, useMemo} from "react";
import {useSeparator} from "../../../factory";
import {usePhoneInput} from "./usePhoneInput";
import { useComponentDefaults, useResolvedStyle } from "../../../hooks";


const KitsPhoneComponent =
    (
        {
            ref,
            ...rawProps
        }: IKitsPhoneInput
    ) => {
        const { mergedProps: props, themeStyle, elementStyles } = useComponentDefaults('PhoneInput', rawProps, 'Input');
        const resolvedThemeStyle = useResolvedStyle(themeStyle);
        const resolvedRootStyle = useResolvedStyle(elementStyles?.root || {});

        const {
            isWithCountryCode,
            label,
            value,
            placeholder,
            onChange,
            invalid,
            disabled,
            required,
            errors,
            hideError,
            id,
            defaultCountry,
            inputSize,
            isFloatedLabel,
            leftAddon,
            rightAddon,
            includedCountries,
            excludedCountries,
            outputFormat = 'string',
            attached,
            containerStyle,
            ...rest
        } = props;

        const {nativeProps} = useSeparator<HTMLInputElement>(rest);

        const {
            displayValue,
            e164Value,
            objectValue,
            countryFlagUrl,
            countryISO,
            handleChange,
        } = usePhoneInput({
            value,
            onChange,
            outputFormat,
            isWithCountryCode,
            defaultCountry,
            includedCountries,
            excludedCountries,
        });

        useImperativeHandle(ref, () => ({
            value: outputFormat === 'object' ? (objectValue ?? e164Value) : e164Value,
            setValue: (v: any) => handleChange(typeof v === "string" ? v : ""),
        }));

        const flagAddon = useMemo(() => {
            if (!isWithCountryCode) return leftAddon;

            if (countryFlagUrl) {
                return (
                    <Image
                        src={countryFlagUrl}
                        alt={countryISO ?? ""}
                        w={23}
                        h={23}
                        imageStyle={{width: '100%', height: '100%', objectFit: "contain", borderRadius: 2}}
                    />
                );
            }

            return <Icon name="pi pi-phone" size={'2xs'}/>;
        }, [isWithCountryCode, countryFlagUrl, countryISO, leftAddon]);

        const Element = <KitsInputText
            id={`${id}-phone`}
            value={displayValue}
            onChange={(e: any) => handleChange(e.target.value)}
            invalid={invalid}
            disabled={disabled}
            className={nativeProps.className}
            placeholder={placeholder ?? (isWithCountryCode ? "+1 (555) 123-4567" : "")}
            attached
            localProps={{
                keyfilter: /[\d\s\-+()]/,
                style: (resolvedRootStyle || resolvedThemeStyle),
            }}
        />;

        if (attached) {
            return Element;
        }

        return (
            <KitsContainer
                id={id}
                inputSize={inputSize}
                isFloatedLabel={isFloatedLabel}
                rightAddon={rightAddon}
                leftAddon={flagAddon}
                errors={errors}
                required={required}
                hideError={hideError}
                invalid={invalid}
                label={label}
                containerStyle={containerStyle}
            elementStyles={elementStyles}
            >
                {Element}
            </KitsContainer>
        );
    }


export default KitsPhoneComponent;
